// // This module implements a 2-to-1 multiplexer where the output 'f' is set to the value of input 'b' when the select line 's' is LOW (0), and it outputs the value of input 'a' when 's' is HIGH (1).
module top_module(a, b, s, f);input a;
    input b;
    input s;
    output f;

    assign f = (~s)&a || s&b;endmodule
